SELECT TOP __[POSTCOMPILE_param_1] grouping(s.event_month) * :grouping_1 + grouping(s.lag_day) * :grouping_2 + grouping(s.load_epoch_day) * :grouping_3 + :param_2 + :param_3 AS grouping_id, s.event_month AS event_month, s.lag_day AS lag_day, s.load_epoch_day AS load_epoch_day, max(s.batch_id) AS batch_id, max(s.alt_value) AS alt_value, coalesce(sum(s.is_probe_row), :coalesce_1) AS row_count, coalesce(sum(s.is_eligible), :coalesce_2) AS n_curve_eligible, coalesce(sum(s.is_null_event_time), :coalesce_3) AS n_null_event_time, coalesce(sum(s.is_null_load_time_only), :coalesce_4) AS n_null_load_time_only, coalesce(sum(s.is_negative_clipped), :coalesce_5) AS n_negative_clipped, coalesce(sum(s.is_negative_lag_excluded), :coalesce_6) AS n_negative_lag_excluded, coalesce(sum(s.is_overflow), :coalesce_7) AS n_overflow, coalesce(sum(s.is_join_unmatched), :coalesce_8) AS n_join_unmatched, CAST(:param_4 AS BIGINT) AS n_other_exclusions, coalesce(sum(s.is_base_row), :coalesce_9) AS n_base_rows, coalesce(sum(s.is_ambiguous_base), :coalesce_10) AS n_ambiguous_base_rows, coalesce(sum(s.is_compare_mismatch), :coalesce_11) AS n_compare_mismatch, max(s.lookup_dup) AS max_lookup_dup, count(*) AS n_staged_rows, CAST(NULL AS BIGINT) AS distinct_keys, min(s.load_time) AS min_load_time 
FROM (SELECT CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= :param_5 OR demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < :param_6) THEN DATEFROMPARTS(YEAR(demo_retail.dbo.orders.order_date), MONTH(demo_retail.dbo.orders.order_date), 1) ELSE NULL END AS event_month, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < :param_6) THEN :param_7 WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= :param_5 AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) > :param_8) THEN :param_9 WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= :param_5 AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < :param_10) THEN :param_11 WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= :param_5) THEN DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) ELSE NULL END AS lag_day, CAST(demo_retail.dbo.orders.loaded_at AS DATE) AS load_epoch_day, CAST(NULL AS VARCHAR(max)) AS batch_id, CAST(NULL AS VARCHAR(max)) AS alt_value, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= :param_5) THEN :param_12 ELSE :param_13 END AS is_eligible, CASE WHEN (demo_retail.dbo.orders.order_date IS NULL) THEN :param_14 ELSE :param_15 END AS is_null_event_time, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NULL) THEN :param_16 ELSE :param_17 END AS is_null_load_time_only, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= :param_18 AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < :param_19) THEN :param_20 ELSE :param_21 END AS is_negative_clipped, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < :param_6) THEN :param_22 ELSE :param_23 END AS is_negative_lag_excluded, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= :param_5 AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) > :param_24) THEN :param_25 ELSE :param_26 END AS is_overflow, CAST(:param_27 AS INTEGER) AS is_join_unmatched, CAST(:param_28 AS INTEGER) AS is_base_row, CAST(:param_29 AS INTEGER) AS is_ambiguous_base, CAST(:param_30 AS INTEGER) AS is_compare_mismatch, CAST(:param_31 AS INTEGER) AS is_probe_row, CAST(NULL AS INTEGER) AS lookup_dup, CAST(NULL AS VARCHAR(max)) AS key_hash, demo_retail.dbo.orders.loaded_at AS load_time 
FROM demo_retail.dbo.orders 
WHERE demo_retail.dbo.orders.loaded_at <= :as_of OR demo_retail.dbo.orders.loaded_at IS NULL) AS s GROUP BY GROUPING SETS ((s.event_month, s.lag_day), (s.load_epoch_day))
